VALUES
  ('public-health-specialist-moex-00212', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '有關健康促進計畫目標（objectives）的擬定，下列敘述何者錯誤？', '["衝擊目標（impactobjectives）包含學習目標、行為目標與環境目標", "過程目標（processobjectives）是針對介入計畫過程的陳述，包含計畫執行中所使用的各種策略", "目標的設定不需要考慮時間的限制，但必須要清晰明確、特定、可測量且切實可行", "目標的設定除了需清晰明確外，還需要讓各層級針對計畫進行溝通，以利後續的推行"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00213', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關正向情緒（positiveemotion）的測量，何者正確？', '["測量的方法只能用自陳式量表", "生理測量不會受到情境的影響", "生理測量的進行是相對方便的", "自陳式的測量會受到社會期許的影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00214', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '在評價一個健康促進方案或計畫時，調查目標對象的滿意度是在進行什麼評價？', '["總結性評價（summativeevaluation）", "形成性評價（formativeevaluation）", "衝擊評價（impactevaluation）", "結果評價（outcomeevaluation）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00215', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關於「健康倡議（healthadvocacy）」的敘述何者錯誤？', '["相較於社會行銷著重在政策或制度的改變，健康倡議著重在個人行動上的改變", "健康倡議主要聚焦在影響健康的社會決定因子，以及社會上的健康不平等現象", "進行健康倡議時，必須要有完整的策略，來改變影響健康的政策及社會環境", "健康倡議的行動是多元的，包括：投書、擔任政策制訂的諮詢、參與社會運動等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00216', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '健康倡議需要媒體的倡議來支持。下列有關媒體倡議（mediaadvocacy）的敘述何者錯誤？', '["有別於傳統健康傳播利用媒體來改變行為，媒體倡議希望改變的是社會層次的相關政策", "進行媒體倡議的第一步是針對訊息進行設計，藉此告訴閱聽人什麼是重要的及如何解讀", "媒體倡議的最後一步是規劃媒體近用（mediaaccess）策略，以讓倡議的訊息被媒體採用", "傳統健康傳播強調縮短知識或態度的差距，而媒體倡議強調縮短權力的差距（powergap）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00217', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列對健康倡議的敘述何者正確？', '["政策倡議時應先確認跟那些人結盟", "政策倡議時一定要跟媒體合作", "政策倡議時應對立法機關做到賦權（empowerment）", "政策倡議時應先確認要達到的環境改變是什麼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00218', 'public-health-specialist', 'public-health-specialist-moex-113-d1d05825', 'sub-public-health-specialist-01', NULL, 'single_choice', '下列有關社會行銷（socialmarketing）的敘述何者正確？', '["社會行銷所面對的競爭者，指的是其他提供類似健康服務的組織或機構", "4P行銷組合策略中的「通路」，指的是各種說服及溝通策略", "6P行銷組合是在既有的4P行銷組合中，加入「公共關係」與「政策」", "社會行銷不需要考慮目標對象的特性及需求，即可設計相關行銷策略"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "00c4cab3d6f0", "answer_pdf_sha1": "24ecb6050425", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0806", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "健康社會行為學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00219', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '在2020年進行的一項調查中，美國18歲以上的白人男性和黑人男性吸
菸盛行率分別是24.1%與23.9%。不論種族，除了65歲以上男性的吸菸
盛行率有明顯下降外，吸菸盛行率隨年齡增加的變化並不大。不過上述
白人和黑人男性之間吸菸盛行率的微小差異（0.2%）並未考慮到2020年
白人男性 65 歲以上人口占比較同年齡黑人男性的人口占比高出許多的
事實。經過年齡調整後，你預期種族間男性吸菸盛行率差異會更大、更
小（或反轉）、還是不變？請說明你的理由。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00220', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '某研究招募 100,562 名年齡介於 40 至 79 歲之間的民眾進行低劑量電
腦斷層掃描之肺癌篩檢研究，並從中發現 219 名罹患肺癌之民眾，經
過5年追蹤後，共有127人（58%）死亡，這些死亡者的平均存活時間
為4.1年。根據文獻指出，肺癌病人整體的5年累積存活率約為26%，
而發病後5年內死亡者之平均存活時間約為3.3年。根據上述數據，研
究者是否可以作以下結論：接受低劑量電腦斷層掃描之肺癌篩檢，可以
讓篩檢出的肺癌病人延長存活時間，且有較低的致死率？請說明你的
理由。（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00221', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'essay', '下表中的數據來自一項假設性研究，研究雙胞胎在分娩順序與圍產期
死亡率之間的關係。
圍產期死亡數
妊娠週數 雙胞胎妊娠數 b/a
先出生新生兒（a） 後出生新生兒（b）
24-27 703 359 381 1.06
28-31 1,371 98 141 1.44
32-35 2,897 74 164 2.22
≥36  2,935 33 124 3.76
根據這些結果，我們是否可以合理推斷：雙胞胎中後出生新生兒在足月
或接近足月妊娠中圍產期死亡風險增加是一個特別值得關注的問題，但
在未足月的妊娠中這個問題就比較不嚴重？請說明你的理由。（20分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00222', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關年齡標準化死亡率的計算以及比較不同地區年齡標準化死亡率之敘述，何者錯誤？', '["對於同一個地區，年齡標準化死亡率會隨著標準人口選擇之不同而有不同", "兩個地區的年齡標準化死亡率即使相同，也無法判定其年齡別死亡率是否相同", "礙於有時某年齡層人數少，造成年齡別疾病率的大幅變動，因此可以針對特殊疾病率穩定 的年齡層進行標準化", "兩地的粗死亡率不同，但年齡別疾病率相同，因此無論標準族群選自第三地區或是合併兩 地區之人口，兩地之標準化死亡率不一定相同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00223', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某研究者歷經二年時間隨機抽樣調查訪問年齡為50歲以上之2,600位婦女，其中有170位婦 女自我報告曾罹患子宮頸癌、280位罹患過乳癌、另外有360位婦女經歷子宮切除。追蹤此群 婦女15年後，共有20名婦女罹患子宮頸癌。試問此群婦女在追蹤期間的子宮頸癌發生危險性 為下列何者？', '["每千人分之9.66", "每千人分之8.23", "每千人分之11.17", "每千人分之91.7"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00224', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於發生率和盛行率的敘述，下列何者錯誤？', '["發生率的分子為某一特定期間內族群的新發病例數", "盛行率的分母為特定期間內族群的總人口數", "橫斷面研究無法計算發生率", "規劃醫療資源和健康服務的配置，發生率是比較好的參考指標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00225', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '一個橫斷式研究發現甲疾病在族群的盛行率為20%，而甲疾病在診斷後的平均存活時間為10 年，請問甲疾病每年的發生率為下列何者？', '["2.5%", "2.0%", "20%", "10%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00226', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '有關各國政府所公布平均餘命之敘述，下列何者錯誤？', '["由於醫療保健隨著年代進步，所以針對目前各年齡層的死亡機率所推算出來的當代各年齡 的平均餘命，會較實際上各年齡層的真正壽命要短", "平均餘命是採用世代生命表法來計算，亦即從某一年各年齡別死亡率來估計一世代從出生 到死亡的死亡率", "平均餘命是指假定各年齡層的死亡機率保持不變的情形下，預期可以存活的平均年數", "利用平均餘命來計算人年損失或工作年損失，可用以評估不同疾病或死因的相對重要性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00227', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '愛滋病毒（HumanImmunodeficiencyVirus）是後天免疫缺乏症候群（AcquiredImmunodeficiency Syndrome,AIDS）的何種因子？', '["充分因子", "必要因子", "非充分且非必要因子", "必要且充分因子"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00228', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '失智症疾病自然史中，有研究發現先天ApolipoproteinE（ApoE）基因缺陷可能會增加未來罹 患失智症風險。其中個體帶有先天ApoE基因缺陷為下列何種疾病自然史階段？', '["易感受期", "臨床前期", "臨床期", "潛伏期"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00229', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '若已知引發心臟病發生的充分因子有四個，如下圖。其中促成因子B所造成的病因分率為下 列何者？', '["12%", "100%", "75%", "35%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00230', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '關於因果關係的判斷，下列敘述何者錯誤？', '["某研究發現A暴露與B疾病的相關性統計學上不顯著，因此可推論A暴露與B疾病沒有 因果關係", "以橫斷性的問卷詢問參與者目前的抽菸習慣與有無心血管疾病，以探討抽菸與心血管疾病 的因果關係，可能發生倒因為果（reversecausality）的謬誤", "小美得了乳癌後接受放射線治療兩年後，又被診斷甲狀腺癌，可以判斷甲狀腺癌可能是由 放射線治療所引起，因為符合時序性（temporality）", "使用制酸劑與使用抗生素根除幽門桿菌具有相同的十二指腸潰瘍的治癒率，但研究發現使 用制酸劑的人潰瘍容易復發，而使用抗生素殺死幽門桿菌的人不容易復發，提供很強的證 據顯示幽門桿菌與十二指腸潰瘍有因果關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00231', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某學者於今年欲透過分析臺灣健保資料庫，收集 2005～2018 年間被臨床醫師診斷為第二型 糖尿病患者，且收集每年靠近研究對象居住地址最近的環境部空氣品質監測站之空污指標 PM 數值，追蹤至2021年，觀察PM 數值高低是否和新發急性腎衰竭有關。試問此一研究過', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 10, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
  ('public-health-specialist-moex-00232', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '5 2.5 程為下列何種研究設計？', '["橫斷研究（cross-sectionalstudy）", "病例世代研究（case-cohortstudy）", "巢式病例對照研究（nestedcase-controlstudy）", "回溯性世代追蹤研究（retrospectivecohortstudy）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
