  ('public-health-specialist-moex-00234', 'public-health-specialist', 'public-health-specialist-moex-113-aaf759af', 'sub-public-health-specialist-02', NULL, 'single_choice', '某醫院收治66名急性心肌梗塞患者，研究者定義每位患者其心肌梗塞發作前7天為暴露期， 針對同一病例，事件發生前1個月的7天作為對照期，欲利用問卷訪視方式，收集並比較暴 露期和對照期的睡眠品質好壞是否與心肌梗塞發生有關。有關此研究設計方法，下列敘述何 者錯誤？', '["此研究設計為配對研究設計之一種，可利用條件式羅吉斯迴歸（Conditional logistic regression）進行分析", "用於研究急性事件與短期暴露之間的一種研究方法", "以自己作為對照組，其優勢為可避免干擾偏差之影響", "此研究設計前提條件之一為不適用於長期的累積暴露評估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:36+00:00", "source_pdf_sha1": "8bdb1f273030", "answer_pdf_sha1": "cb646a1d0b7f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "108", "s": "0803", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "流行病學", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
